#define THREADS_PER_BLOCK 512
#define MAXBLOCKS 65536
#define CUDATIME

// host memory
float *work_mem_h;
float *coord_h;

// device memory (simulated with host pointers for OpenMP)
float *work_mem_d;
float *coord_d;
int   *center_table_d;
bool  *switch_membership_d;
Point *p;

static int iter = 0;		// counter for total# of iteration


//=======================================
// Euclidean Distance
//=======================================
// This function is now a regular C++ function, not a __device__ function.
// The 'coord_d' parameter is now a host pointer.
float
d_dist(int p1, int p2, int num, int dim, float *coord_d)
{
	float retval = 0.0;
	for(int i = 0; i < dim; i++){
		float tmp = coord_d[(i*num)+p1] - coord_d[(i*num)+p2];
		retval = retval + (tmp * tmp);
	}
	return retval;
}

//=======================================
// Kernel - Compute Cost
//=======================================
// This is now a regular C++ function, not a __global__ function.
// OpenMP pragmas are used for parallelization.
void
kernel_compute_cost(int num, int dim, long x, Point *p_arr, int K, int stride,
					float *coord_d_arr, float *work_mem_d_arr, int *center_table_d_arr, bool *switch_membership_d_arr)
{
	// Parallelize the loop over the number of points
	#pragma omp parallel for schedule(static)
	for(int tid = 0; tid < num; tid++)
	{
		float *lower = &work_mem_d_arr[tid*stride];

		// cost between this point and point[x]: euclidean distance multiplied by weight
		float x_cost = d_dist(tid, x, num, dim, coord_d_arr) * p_arr[tid].weight;

		// if computed cost is less then original (it saves), mark it as to reassign
		if ( x_cost < p_arr[tid].cost )
		{
			switch_membership_d_arr[tid] = 1;
			lower[K] += x_cost - p_arr[tid].cost;
		}
		// if computed cost is larger, save the difference
		else
		{
			lower[center_table_d_arr[p_arr[tid].assign]] += p_arr[tid].cost - x_cost;
		}
	}
}

//=======================================
// Allocate Device Memory (simulated)
//=======================================
void allocDevMem(int num, int dim)
{
	// In OpenMP, we use host memory directly.
	// These allocations are for consistency with the CUDA version's structure.
	center_table_d = (int*) malloc( num * sizeof(int) );
	switch_membership_d = (bool*) malloc( num * sizeof(bool) );
	p = (Point*) malloc( num * sizeof(Point) );
	coord_d = (float*) malloc(num * dim * sizeof(float));
}

//=======================================
// Allocate Host Memory
//=======================================
void allocHostMem(int num, int dim)
{
	coord_h	= (float*) malloc( num * dim * sizeof(float) );
}

//=======================================
// Free Device Memory (simulated)
//=======================================
void freeDevMem()
{
	free(center_table_d);
	free(switch_membership_d);
	free(p);
	free(coord_d);
}

//=======================================
// Free Host Memory
//=======================================
void freeHostMem()
{
	free(coord_h);
}

//=======================================
// pgain Entry - OpenMP SETUP + CALL
//=======================================
float pgain( long x, Points *points, float z, long int *numcenters, int kmax, bool *is_center, int *center_table, bool *switch_membership, bool isCoordChanged,
							double *serial_t, double *cpu_to_gpu_t, double *gpu_to_cpu_t, double *alloc_t, double *kernel_t, double *free_t)
{	
#ifdef CUDATIME
	double tmp_t;
	double start_time, stop_time;

	start_time = omp_get_wtime();
#endif

	int stride	= *numcenters + 1;			// size of each work_mem segment
	int K		= *numcenters ;				// number of centers
	int num		=  points->num;				// number of points
	int dim		=  points->dim;				// number of dimension
	int nThread =  num;						// number of threads == number of data points

	//=========================================
	// ALLOCATE HOST MEMORY + DATA PREPARATION
	//=========================================
	work_mem_h = (float*) malloc(stride * (nThread + 1) * sizeof(float) );
	// Only on the first iteration
	if(iter == 0)
	{
		allocHostMem(num, dim);
	}

	// build center-index table
	int count = 0;
	for( int i=0; i<num; i++ )
	{
		if( is_center[i] )
		{
			center_table[i] = count++;
		}
	}

	// Extract 'coord'
	// Only if first iteration OR coord has changed
	if(isCoordChanged || 0 == iter)
	{
		for(int i=0; dim > i; i++)
		{
			for(int j=0; num > j; j++)
			{
				coord_h[ (num*i)+j ] = points->p[j].coord[i];
			}
		}
	}

#ifdef CUDATIME
	stop_time = omp_get_wtime();
	*serial_t += (stop_time - start_time);

	start_time = omp_get_wtime();
#endif

	//=======================================
	// ALLOCATE DEVICE MEMORY (simulated)
	//=======================================
	// In OpenMP, we reuse host memory. These are for consistency.
	if( 0 == iter )
	{
		allocDevMem(num, dim);
	}

#ifdef CUDATIME
	stop_time = omp_get_wtime();
	*alloc_t += (stop_time - start_time);

	start_time = omp_get_wtime();
#endif

	//=======================================
	// CPU-TO-GPU MEMORY COPY (simulated)
	//=======================================
	// Only if first iteration OR coord has changed
	if(isCoordChanged || 0 == iter)
	{
		// Copy coord_h to coord_d
		memcpy(coord_d, coord_h, num * dim * sizeof(float));
	}
	// Copy center_table and points data
	memcpy(center_table_d, center_table, num * sizeof(int));
	memcpy(p, points->p, num * sizeof(Point));

	// Reset switch_membership and work_mem
	memset(switch_membership_d, 0, num * sizeof(bool));
	memset(work_mem_d, 0, stride * (nThread + 1) * sizeof(float));

#ifdef CUDATIME
	stop_time = omp_get_wtime();
	*cpu_to_gpu_t += (stop_time - start_time);

	start_time = omp_get_wtime();
#endif

	//=======================================
	// KERNEL: CALCULATE COST
	//=======================================
	// The kernel_compute_cost function is now parallelized with OpenMP.
	kernel_compute_cost(num, dim, x, p, K, stride, coord_d, work_mem_d, center_table_d, switch_membership_d);

	// In OpenMP, synchronization is implicit with parallel regions or explicit barriers.
	// For this kernel, the #pragma omp parallel for handles synchronization.

#ifdef CUDATIME
	stop_time = omp_get_wtime();
	*kernel_t += (stop_time - start_time);

	start_time = omp_get_wtime();
#endif

	//=======================================
	// GPU-TO-CPU MEMORY COPY (simulated)
	//=======================================
	// Copy work_mem_h back from work_mem_d
	memcpy(work_mem_h, work_mem_d, stride * (nThread + 1) * sizeof(float));
	// Copy switch_membership back from switch_membership_d
	memcpy(switch_membership, switch_membership_d, num * sizeof(bool));

#ifdef CUDATIME
	stop_time = omp_get_wtime();
	*gpu_to_cpu_t += (stop_time - start_time);

	start_time = omp_get_wtime();
#endif

	//=======================================
	// CPU (SERIAL) WORK
	//=======================================
	int number_of_centers_to_close = 0;
	float gl_cost_of_opening_x = z;
	float *gl_lower = &work_mem_h[stride * nThread];
	// compute the number of centers to close if we are to open i
	for(int i=0; num > i; i++)
	{
		if( is_center[i] )
		{
			float low = z;
		    for( int j = 0; num > j; j++ )
			{
				low += work_mem_h[ j*stride + center_table[i] ];
			}

		    gl_lower[center_table[i]] = low;

		    if ( low > 0 )
			{
				++number_of_centers_to_close;
				work_mem_h[i*stride+K] -= low;
		    }
		}
		gl_cost_of_opening_x += work_mem_h[i*stride+K];
	}

	//if opening a center at x saves cost (i.e. cost is negative) do so; otherwise, do nothing
	if ( 0 > gl_cost_of_opening_x )
	{
		// Parallelize the update of points' cost and assignment
		#pragma omp parallel for schedule(static)
		for(int i = 0; i < num; i++)
		{
			bool close_center = gl_lower[center_table[p[i].assign]] > 0 ;
			if ( switch_membership[i] || close_center )
			{
				points->p[i].cost = dist(points->p[i], points->p[x], dim) * points->p[i].weight;
				points->p[i].assign = x;
			}
		}

		// Parallelize the update of is_center status
		#pragma omp parallel for schedule(static)
		for(int i = 0; i < num; i++)
		{
			if( is_center[i] && 0 < gl_lower[center_table[i]] )
			{
				is_center[i] = false;
			}
		}

		if( 0 <= x && x < num)
		{
			is_center[x] = true;
		}
		*numcenters = *numcenters + 1 - number_of_centers_to_close;
	}
	else
	{
		gl_cost_of_opening_x = 0;
	}

	//=======================================
	// DEALLOCATE HOST MEMORY
	//=======================================
	free(work_mem_h);


#ifdef CUDATIME
	stop_time = omp_get_wtime();
	*serial_t += (stop_time - start_time);

	start_time = omp_get_wtime();
#endif

	//=======================================
	// DEALLOCATE GPU MEMORY (simulated)
	//=======================================
	// In OpenMP, we just free the host memory allocated for simulation.
	// This is called in the main streamCluster function.

#ifdef CUDATIME
	stop_time = omp_get_wtime();
	*free_t += (stop_time - start_time);
#endif
	iter++;
	return -gl_cost_of_opening_x;
}
